SELECT ws.station_name, ws.installation_date
FROM weather_stations ws
ORDER BY ws.installation_date ASC;

SELECT df.format_name, df.description 
FROM data_formats df 
JOIN readme_files rf ON df.format_id = rf.format_id;

SELECT station_name, location, latitude, longitude
FROM weather_stations
WHERE status = 'active';

SELECT wd.*, df.*
FROM weather_data wd
JOIN data_files df ON wd.data_id = df.data_id;
